DAYS = 30
now_ts   = int(time.time())
start_ts = now_ts - DAYS * 86400

def strip_html(s):
    return re.sub(r"<[^>]+>", " ", s or "").strip()

def ic_post(path, body):
    url = "https://api.intercom.io" + path
    data = json.dumps(body).encode()
    req = Request(url, data=data, headers={
        "Authorization": f"Bearer {TOKEN}",
        "Accept": "application/json",
        "Content-Type": "application/json",
        "Intercom-Version": "2.11"
    })
    try:
        with urlopen(req, timeout=30) as r:
            return json.loads(r.read())
    except HTTPError as e:
        body = e.read().decode()
        print(f"  HTTP {e.code}: {body[:200]}")
        raise

matched  = []
cursor   = None
page     = 0
total_ic = 0

print(f"Fetching conversations from last {DAYS} days (since {datetime.fromtimestamp(start_ts).strftime('%Y-%m-%d')})...")

while True:
    body = {
        "query": {
            "operator": "AND",
            "value": [{"field": "created_at", "operator": ">", "value": start_ts}]
        },
        "pagination": {"per_page": 150}
    }
    if cursor:
        body["pagination"]["starting_after"] = cursor

    page += 1
    print(f"  Page {page} — {len(matched)} matched so far...", end="\r", flush=True)

    data = ic_post("/conversations/search", body)
    convs = data.get("conversations", [])
    if page == 1:
        total_ic = data.get("total_count", 0)
        print(f"  Total in Intercom: {total_ic}")

    hit_floor = False
    for c in convs:
        ts = c.get("created_at", 0)
        if ts < start_ts:
            hit_floor = True
            continue

        email = (c.get("source") or {}).get("author", {}).get("email") or ""
        email = email.lower()
        domain = email.split("@")[1] if "@" in email else ""
        if not domain or domain not in DOMAIN_LOOKUP:
            continue

        entries = DOMAIN_LOOKUP[domain]
        if not entries:
            continue
        e = entries[0]

        state = c.get("state") or ("open" if c.get("open") else "closed")
        ticket = c.get("ticket") or {}
        if ticket.get("state") == "submitted":
            state = "submitted"

        ca = c.get("custom_attributes") or {}
        _tt = ticket.get("ticket_type")
        ticket_type_name = _tt.get("name", "") if isinstance(_tt, dict) else (_tt or "")
        # kind: "ticket" if conversation has a ticket type, otherwise "chat"
        kind = "ticket" if ticket_type_name else "chat"
        # proper Intercom ID from custom attributes (for building direct links)
        intercom_link_id = str(ca.get("ID", "") or c["id"])
        # product sentiment
        sentiment = str(ca.get("Product sentiment", "") or "").strip()
        matched.append({
            "id": c["id"],
            "intercom_link_id": intercom_link_id,
            "created_at": ts,
            "state": state,
            "priority": c.get("priority", "not_priority"),
            "ticket_type": ticket_type_name,
            "kind": kind,
            "sentiment": sentiment,
            "body": strip_html((c.get("source") or {}).get("body", "")),
            "subject": strip_html((c.get("source") or {}).get("subject", "")),
            "ai_title": ca.get("AI Title", ""),
            "author_email": email,
            "author_name": (c.get("source") or {}).get("author", {}).get("name", "") or "",
            "sla_name": (c.get("sla_applied") or {}).get("sla_name", ""),
            "csm": e["c"],
            "account": e["a"],
            "domain": domain
        })

    cursor = (data.get("pages") or {}).get("next", {}).get("starting_after") if isinstance((data.get("pages") or {}).get("next"), dict) else None
    if not cursor or hit_floor:
        break

print(f"\nDone. Intercom total: {total_ic} | Matched: {len(matched)}")

output = {
    "generated_at": now_ts,
    "generated_date": datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M UTC"),
    "days": DAYS,
    "total_intercom": total_ic,
    "total_matched": len(matched),
    "tickets": matched
}

with open("data.json", "w") as f:
    json.dump(output, f, separators=(",", ":"))

print(f"Wrote data.json ({len(matched)} matched tickets)")
